WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/35.0/apex.js")}
{!REQUIRESCRIPT("/soap/ajax/35.0/connection.js")}


var pageUrl; 

if('{!$Label.mogli_sms__namespace}' === "none"){
pageUrl="/apex/" + "SendSMS"; 
} else { 
pageUrl="/apex/" + '{!$Label.mogli_sms__namespace}' + "SendSMS"; 
}





var recordIds = {!GETRECORDIDS( $ObjectType.Contact )};

if (recordIds[0] == null){
alert("Please select at least one record to send.")
}
else{
pageUrl = pageUrl+'?ids='+recordIds;
parent.location.href = pageUrl;
}
